// Normalize the raw intake payload into a clean client record
const body = $input.first().json.body ?? $input.first().json;

// ── Derive tags from answers ──────────────────────────────────────────
const tags = [];

// Security tier
if (body.compliance_level?.startsWith('Formal')) tags.push('security:formal');
else if (body.compliance_level?.startsWith('Basic')) tags.push('security:basic');
else tags.push('security:informal');

// Cloud
if (body.cloud_provider && body.cloud_provider !== 'None / not sure')
  tags.push(`cloud:${body.cloud_provider.toLowerCase()}`);

// Focus area
const focusMap = {
  'Client reporting':              'focus:reporting',
  'Lead intake and routing':       'focus:lead-routing',
  'Content and campaign operations': 'focus:content-ops',
  'Back-office / billing':         'focus:back-office',
};
if (focusMap[body.pain_point_primary]) tags.push(focusMap[body.pain_point_primary]);

// Team size
tags.push(`team:${body.team_size ?? 'unknown'}`);

// Tool surface (first 5 for tagging)
const allTools = [
  ...(body.tools_crm ?? []),
  ...(body.tools_project_mgmt ?? []),
  ...(body.tools_comms ?? []),
  ...(body.tools_billing ?? []),
].filter(t => t !== 'Other').slice(0, 5);
allTools.forEach(t => tags.push(`tool:${t.toLowerCase().replace(/[^a-z0-9]/g, '-')}`));

// ── Build normalized record ───────────────────────────────────────────
return [{
  json: {
    submitted_at: new Date().toISOString(),
    // Company
    company_name:   body.company_name,
    website:        body.website,
    contact_name:   body.contact_name,
    contact_email:  body.contact_email,
    team_size:      body.team_size,
    // Pain
    pain_primary:   body.pain_point_primary === 'Other'
                      ? body.pain_point_primary_other
                      : body.pain_point_primary,
    pain_desc:      body.pain_description,
    outcome_30d:    body.outcome_30_days,
    // Infra
    cloud:          body.cloud_provider,
    source_of_truth: body.source_of_truth,
    automation_platforms: (body.automation_platforms ?? []).join(', '),
    systems_off_limits: body.systems_off_limits ?? '',
    // Security
    compliance:     body.compliance_level,
    compliance_detail: body.compliance_detail ?? '',
    approver_name:  body.approver_name ?? '',
    approver_email: body.approver_email ?? '',
    // Tools (raw)
    tools_crm:     (body.tools_crm ?? []).join(', '),
    tools_pm:      (body.tools_project_mgmt ?? []).join(', '),
    tools_comms:   (body.tools_comms ?? []).join(', '),
    tools_ads:     (body.tools_marketing_ads ?? []).join(', '),
    tools_email:   (body.tools_email_automation ?? []).join(', '),
    tools_billing: (body.tools_billing ?? []).join(', '),
    tools_data:    (body.tools_data_storage ?? []).join(', '),
    tools_other:   body.tools_other_free_text ?? '',
    // Tags (for Notion multi-select)
    tags: tags,
    tags_str: tags.join(', ')
  }
}];
